mapper.select:
SELECT br.id as reviewId, br.booking_no as bookingNo, br.rating, br.content, br.has_image as hasImage, br.reply_content as replyContent, br.reply_time as replyTime, br.create_time as createTime, br.is_anonymous as isAnonymous, u.nick_name as userName, u.avatar, cb.car_number as carNumber, GROUP_CONCAT(bri.image_url) as images FROM booking_review br LEFT JOIN sys_user u ON br.user_id = u.user_id LEFT JOIN car_booking cb ON br.booking_no = cb.booking_no LEFT JOIN booking_review_image bri ON br.id = bri.review_id WHERE br.dept_id = #{deptId} AND br.status = 1
AND br.rating = #{rating}
AND br.has_image = #{hasImage}
GROUP BY br.id ORDER BY br.create_time DESC

mapper.update:
UPDATE booking_review
SET reply_content = #{replyContent},
    reply_time = NOW(),
    reply_user_id = #{replyUserId}
WHERE id = #{reviewId}

mapper.delete:
DELETE FROM dept_schedule
WHERE dept_id = #{deptId}
  AND work_date >= CURDATE()

mapper.update:
UPDATE dept_car_space
SET status = #{status},
    update_time = NOW()
WHERE dept_id = #{deptId}
  AND space_no = #{spaceNo}
